import React, { useEffect, useState } from "react";
import "./Timesheet.css";

const TimesheetHistory = () => {
  const [history, setHistory] = useState([]);
  const [selectedWeek, setSelectedWeek] = useState(null);

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("timesheet-history")) || [];
    setHistory(data.sort((a, b) => b.timestamp - a.timestamp));
  }, []);

  const viewWeek = (item) => {
    localStorage.setItem("selected-week", item.key);
    window.location.href = "/dashboard/timesheet";
  };

  const viewDayLog = (item) => {
    setSelectedWeek(item);
  };

  return (
    <div className="timesheet-container">

      <h2>Timesheet History</h2>

      {history.length === 0 ? (
        <p style={{ marginTop: "10px" }}>No previous timesheets found.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Week</th>
              <th>Total Hours</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {history.map((item, i) => (
              <tr key={i}>
                <td>{item.weekRange}</td>
                <td>{item.totalHours}</td>

                <td>
                  <span className={`status-badge ${item.status}`}>
                    {item.status}
                  </span>
                </td>

                <td>
                  <button className="view-btn" onClick={() => viewWeek(item)}>
                    Edit
                  </button>

                  <button className="view-btn" onClick={() => viewDayLog(item)}>
                    Day History
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}


      {/* DAY LOG VIEW */}
      {selectedWeek && (
        <div style={{ marginTop: "25px" }}>
          <h3>Day Wise History - {selectedWeek.weekRange}</h3>

          <table>
            <thead>
              <tr>
                <th>Day</th>
                <th>Date</th>
                <th>Activities</th>
                <th>Day Total</th>
              </tr>
            </thead>

            <tbody>
              {selectedWeek.days.map((day, i) => {
                const dayTotal = day.activities.reduce(
                  (s,a)=> s + Number(a.hours || 0), 0
                );

                return (
                  <tr key={i}>
                    <td>{day.day}</td>
                    <td>{day.dateText}</td>

                    <td>
                      {day.activities.length === 0 && <i>No work logged</i>}

                      {day.activities.map((a, j) => (
                        <div key={j} style={{ marginBottom:"6px" }}>
                          <strong>{a.project || "No Project"}:</strong> {" "}
                          {a.hours} hrs
                          <div style={{ fontSize:"12px", color:"#555" }}>
                            {a.description}
                          </div>
                        </div>
                      ))}
                    </td>

                    <td><strong>{dayTotal} hrs</strong></td>
                  </tr>
                );
              })}
            </tbody>
          </table>

        </div>
      )}

    </div>
  );
};

export default TimesheetHistory;
